  const [messageInput, setMessageInput] = useState("");
  const [showSidebar, setShowSidebar] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [messages, setMessages] = useState<Message[]>([]);
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [registeredDescriptors, setRegisteredDescriptors] = useState<number[][] | null>(null);
  const [isFaceLoading, setIsFaceLoading] = useState(true);
  const [confidence, setConfidence] = useState<number | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const detectionIntervalRef = useRef<NodeJS.Timeout | null>(null);
  const matchScoreRef = useRef(0);
  const faceLostTimeRef = useRef<number | null>(null);

  const isSecure = authState === "UNLOCKED";

  const filteredContacts = contacts.filter(c =>
    c.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  useEffect(() => {
    const init = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      setCurrentUser(user);

      if (user) {
        setIsFaceLoading(true);
        try {
          // Fetch Real Contacts
          const { data: profilesData } = await supabase
            .from('profiles')
            .select('*')
            .neq('id', user.id);

          if (profilesData) {
            const formatted = profilesData.map((p: any) => ({
              id: p.id,
              name: p.email ? p.email.split('@')[0] : 'User',
              avatar: p.email ? p.email.charAt(0).toUpperCase() : 'U',
              lastMessage: "Secure exchange available",
              time: "",
              online: true,
              unread: 0
            }));
            setContacts(formatted);
            if (formatted.length > 0) setSelectedContact(formatted[0]);
          }

          await loadFaceModels();
          const { data: faceData, error: faceError } = await supabase
            .from('faces')
            .select('encoding')
            .eq('user_id', user.id)
            .order('created_at', { ascending: false })
            .limit(1)
            .single();

          if (faceError && faceError.code !== 'PGRST116') throw faceError;

          if (faceData) {
            setRegisteredDescriptors(faceData.encoding);
          }
        } catch (err) {
          console.error("Initialization error:", err);
        } finally {
          setIsFaceLoading(false);
        }
      }
    };
    init();

    return () => {
      if (detectionIntervalRef.current) clearInterval(detectionIntervalRef.current);
    };
  }, []);

  useEffect(() => {
    if (!currentUser || !registeredDescriptors || !videoRef.current) return;

    const startDetection = async () => {
      try {
        await startWebcam(videoRef.current!);

        detectionIntervalRef.current = setInterval(async () => {
          if (!videoRef.current) return;

          const faces = await detectFaces(videoRef.current);

          if (faces.length > 1) {
            setAuthState("LOCKED");
            setLockReason("MULTIPLE_FACES");
            setConfidence(null);
            matchScoreRef.current = -2;
            faceLostTimeRef.current = null;
            return;
          }

          if (faces.length === 0) {
            if (!faceLostTimeRef.current) {
              faceLostTimeRef.current = Date.now();
            }
            const timeSinceLost = Date.now() - faceLostTimeRef.current;

            if (timeSinceLost > 800) {
              setAuthState("LOCKED");
              setLockReason("NO_FACE");
              setConfidence(null);
              matchScoreRef.current = -2;
            }
            return;
          }

          faceLostTimeRef.current = null;

          const currentDescriptor = await getFaceDescriptor(videoRef.current);
          if (currentDescriptor && registeredDescriptors) {
            const result = verifyFaceMatchAll(currentDescriptor, registeredDescriptors);
            setConfidence(result.confidence);

            if (result.isMatch) {
              matchScoreRef.current = Math.min(2, matchScoreRef.current + 1);
            } else {
              matchScoreRef.current = Math.max(-2, matchScoreRef.current - 1);
            }

            if (matchScoreRef.current >= 2) {
              setAuthState("UNLOCKED");
              setLockReason(null);
            } else if (matchScoreRef.current <= -2) {
              setAuthState("LOCKED");
              setLockReason("IDENTITY_MISMATCH");
            } else if (authState === "LOCKED") {
              setAuthState("VERIFYING");
            }
          }
        }, 250);
      } catch (err) {
        console.error("Detection loop error:", err);
        setAuthState("LOCKED");
        setLockReason("CAMERA_ERROR");
      }
    };

    startDetection();

    return () => {
      if (detectionIntervalRef.current) clearInterval(detectionIntervalRef.current);
    };
  }, [currentUser, registeredDescriptors, authState]);

  useEffect(() => {
    if (!currentUser) return;

    fetchMessages();

    const channel = supabase
      .channel('public:messages')
      .on('postgres_changes', { 
        event: 'INSERT', 
        schema: 'public', 
        table: 'messages'
      }, (payload) => {
        const newMessage = payload.new;
        if (newMessage.sender_id === currentUser.id || newMessage.receiver_id === currentUser.id) {
          decrypt(newMessage.payload, SHARED_KEY).then(decryptedText => {
            setMessages(prev => [...prev, {
              id: newMessage.id,
              text: decryptedText,
              sent: newMessage.sender_id === currentUser.id,
              time: new Date(newMessage.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
              sender_id: newMessage.sender_id
            }]);
          });
        }
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [currentUser, selectedContact]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const fetchMessages = async () => {
    if (!currentUser || !selectedContact) return;
    const { data, error } = await supabase
      .from('messages')
      .select('*')
      .or(`and(sender_id.eq.${currentUser.id},receiver_id.eq.${selectedContact.id}),and(sender_id.eq.${selectedContact.id},receiver_id.eq.${currentUser.id})`)
      .order('created_at', { ascending: true });

    if (error) {
      console.error("Error fetching messages:", error);
    } else {
      const decryptedMessages = await Promise.all(data.map(async m => ({
        id: m.id,
        text: await decrypt(m.payload, SHARED_KEY),
        sent: m.sender_id === currentUser.id,
        time: new Date(m.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        sender_id: m.sender_id
      })));
      setMessages(decryptedMessages);
    }
  };

  const handleSendMessage = async () => {
    if (!messageInput.trim() || !currentUser || !selectedContact) return;

    const encryptedPayload = await encrypt(messageInput.trim(), SHARED_KEY);
    const newMessage = {
      sender_id: currentUser.id,
      receiver_id: selectedContact.id,
      payload: encryptedPayload,
    };

    const { error } = await supabase.from('messages').insert([newMessage]);

    if (error) {
      toast.error("Failed to send message");
    } else {
      setMessageInput("");
    }
  };

  const handleLogout = async () => {
    try {
      await supabase.auth.signOut();
      toast.success("Successfully logged out");
      navigate("/");
    } catch (error: any) {
      toast.error(error.message || "Failed to logout");
    }
  };

  return (
    <div className="h-screen flex bg-background overflow-hidden relative font-sans">
      <div className={cn(
        "flex flex-col border-r border-border/50 bg-card/30 backdrop-blur-xl transition-all duration-300",
        showSidebar ? "w-80" : "w-0 overflow-hidden",
        "max-md:absolute max-md:inset-y-0 max-md:left-0 max-md:z-40",
        !showSidebar && "max-md:hidden"
      )}>
        <div className="p-4 border-b border-border/30">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-2">
              <div className="w-9 h-9 rounded-xl gradient-btn flex items-center justify-center">
                <Shield className="w-4 h-4 text-primary-foreground" />
              </div>
              <span className="font-bold text-foreground">Secure<span className="text-gradient">Chat</span></span>
            </div>
            <button className="md:hidden text-muted-foreground" onClick={() => setShowSidebar(false)}>
              <ChevronLeft className="w-5 h-5" />
            </button>
          </div>

          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
            <input
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search conversations..."
              className="w-full bg-muted/50 rounded-xl pl-9 pr-4 py-2.5 text-sm text-foreground placeholder:text-muted-foreground outline-none border border-border/30 focus:border-primary/40 transition-colors"
            />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto py-2">
          {filteredContacts.map((contact) => (
            <button
              key={contact.id}
              onClick={() => { setSelectedContact(contact); setShowSidebar(window.innerWidth >= 768); }}
              className={cn(
                "w-full flex items-center gap-3 px-4 py-3 transition-all duration-200 hover:bg-muted/30",
                selectedContact.id === contact.id && "bg-muted/40 border-r-2 border-primary"
              )}
            >
              <div className="relative shrink-0">
                <div className={cn(
                  "w-11 h-11 rounded-full flex items-center justify-center text-sm font-semibold",
                  "bg-gradient-to-br from-primary/30 to-secondary/30 text-foreground"
                )}>
                  {contact.avatar}
                </div>
                {contact.online && (
                  <div className="absolute -bottom-0.5 -right-0.5 w-3.5 h-3.5 rounded-full bg-accent border-2 border-card" />
                )}
              </div>

              <div className="flex-1 min-w-0 text-left">
                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium text-foreground truncate">{contact.name}</span>
                  <span className="text-[10px] text-muted-foreground shrink-0">{contact.time}</span>
                </div>
                <p className="text-xs text-muted-foreground truncate mt-0.5">{contact.lastMessage}</p>
              </div>
            </button>
          ))}
        </div>
      </div>

      <div className="flex-1 flex flex-col min-w-0">
        <div className="h-16 flex items-center justify-between px-4 border-b border-border/30 glass-strong shrink-0">
          <div className="flex items-center gap-3">
            <button className="md:hidden text-muted-foreground mr-1" onClick={() => setShowSidebar(true)}>
              <Users className="w-5 h-5" />
            </button>
            {selectedContact ? (
              <>
                <div className="w-9 h-9 rounded-full bg-gradient-to-br from-primary/30 to-secondary/30 flex items-center justify-center text-sm font-semibold text-foreground">
                  {selectedContact.avatar}
                </div>
                <div>
                  <h3 className="text-sm font-semibold text-foreground">{selectedContact.name}</h3>
                  <p className="text-[11px] text-muted-foreground">
                    {selectedContact.online ? "Online" : "Last seen recently"}
                  </p>
                </div>
              </>
            ) : (
              <div className="text-sm font-medium text-muted-foreground">
                No active contacts
              </div>
            )}
          </div>

          <div className="flex items-center gap-2">
            <SecurityBadge isSecure={isSecure} />
            <button onClick={handleLogout} className="p-2 rounded-xl hover:bg-muted/50 text-destructive transition-colors" title="Logout">
              <LogOut className="w-4 h-4" />
            </button>
          </div>
        </div>

        <div className={cn(
          "px-4 py-2 flex items-center justify-between transition-all duration-500 text-xs font-bold uppercase tracking-widest border-b border-border/20",
          authState === "UNLOCKED" ? "bg-accent/10 text-accent" : 
          authState === "VERIFYING" ? "bg-primary/10 text-primary animate-pulse" : 
          "bg-destructive/10 text-destructive"
        )}>
          <div className="flex items-center gap-2">
            {authState === "UNLOCKED" ? (
              <><Unlock className="w-3 h-3" /> Secure View Active</>
            ) : authState === "VERIFYING" ? (
              <><Loader2 className="w-3 h-3 animate-spin" /> Verifying Identity...</>
            ) : (
              <><Lock className="w-3 h-3" /> 
                {lockReason === "MULTIPLE_FACES" ? "SHOULDER SURFING DETECTED" : 
                 lockReason === "NO_FACE" ? "USER AWAY - VAULT LOCKED" : 
                 lockReason === "IDENTITY_MISMATCH" ? "IDENTITY VERIFICATION FAILED" :
                 "Biometric Lock Active"}
              </>
            )}
          </div>
          {confidence !== null && authState !== "LOCKED" && (
            <div className="flex items-center gap-2 font-mono bg-background/40 px-2 py-0.5 rounded backdrop-blur-sm shadow-sm border border-border/20">
              <span className="opacity-80">MATCH:</span>
              <span className={cn(
                "font-bold",
                confidence > 80 ? "text-green-500" : confidence > 60 ? "text-yellow-500" : "text-destructive"
              )}>{confidence}%</span>
            </div>
          )}
        </div>

        <div className="flex-1 overflow-y-auto px-4 py-6 space-y-4" ref={scrollRef}>
          {authState !== "UNLOCKED" && (
            <div className="flex flex-col items-center justify-center py-10 space-y-4 animate-in fade-in duration-500">
               <div className="w-16 h-16 rounded-3xl bg-destructive/10 flex items-center justify-center border border-destructive/20 neon-glow-red">
                  {lockReason === "MULTIPLE_FACES" ? <AlertTriangle className="w-8 h-8 text-destructive" /> : <Lock className="w-8 h-8 text-destructive" />}
               </div>
               <div className="text-center">
                 <h4 className="text-sm font-bold text-foreground mb-1 uppercase tracking-wider">Messages Encrypted</h4>
                 <p className="text-xs text-muted-foreground max-w-[200px]">
                   {lockReason === "MULTIPLE_FACES" ? "Access suspended. Multiple faces detected in viewing area." : 
                    lockReason === "NO_FACE" ? "Please face the camera to unlock your secure messages." :
                    "Biometric authentication required to reveal message content."}
                 </p>
               </div>
            </div>
          )}

          {messages.length === 0 && authState === "UNLOCKED" && (
            <div className="text-center py-10 text-muted-foreground animate-fade-in">
              <p className="text-sm">No messages yet. Start a secure conversation.</p>
            </div>
          )}

          {messages.map((msg, i) => (
            <MessageBubble
              key={msg.id}
              text={isSecure ? msg.text : "••••••••••••••••••••"}
              sent={msg.sent}
              time={msg.time}
              isSecure={isSecure}
              index={i}
            />
          ))}
        </div>

        <div className="p-4 border-t border-border/30 bg-card/20 shrink-0">
          <form className="flex items-center gap-2" onSubmit={(e) => { e.preventDefault(); handleSendMessage(); }}>
            <button type="button" className="p-2.5 rounded-xl hover:bg-muted/50 text-muted-foreground transition-colors">
              <Paperclip className="w-5 h-5" />
            </button>
            <input
              value={messageInput}
              onChange={(e) => setMessageInput(e.target.value)}
              placeholder={isSecure ? "Type a secure message..." : "Unlock to send messages"}
              disabled={!isSecure}
              className={cn(
                "flex-1 bg-muted/40 rounded-xl px-4 py-3 text-sm text-foreground placeholder:text-muted-foreground outline-none border border-border/30 transition-all duration-300 focus:border-primary/40 focus:shadow-[0_0_15px_hsl(var(--neon-blue)/0.1)]",
                !isSecure && "cursor-not-allowed opacity-50"
              )}
            />
            <GlowButton type="submit" size="sm" className="px-4 py-3 rounded-xl" disabled={!isSecure}>
              <Send className="w-4 h-4" />
            </GlowButton>
          </form>
        </div>
      </div>

      <FaceCameraWidget isSecure={isSecure} onToggle={() => {}} />

      <video 
        ref={videoRef}
        autoPlay 
        muted 
        playsInline 
        className="fixed bottom-0 right-0 w-[1px] h-[1px] opacity-0 pointer-events-none"
      />

      {isFaceLoading && (
        <div className="fixed inset-0 z-[60] bg-background/95 backdrop-blur-xl flex flex-col items-center justify-center">
          <div className="relative mb-8">
            <Loader2 className="w-16 h-16 text-primary animate-spin" />
            <Shield className="absolute inset-0 m-auto w-6 h-6 text-primary" />
          </div>
          <h2 className="text-xl font-bold text-foreground mb-2">Initializing Vault</h2>
          <p className="text-muted-foreground text-sm">Loading neural weights and secure protocols...</p>
        </div>
      )}
    </div>
  );
};

export default ChatPage;

import { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { AnimatedBackground } from "@/components/secure-chat/AnimatedBackground";
import { GlassCard } from "@/components/secure-chat/GlassCard";
import { GlowButton } from "@/components/secure-chat/GlowButton";
import { Check, Scan, User, Loader2, ArrowRight } from "lucide-react";
import { cn } from "@/lib/utils";
import { supabase } from "@/lib/supabase";
import { toast } from "sonner";
import { loadFaceModels, startWebcam, getFaceDescriptor } from "@/services/faceService";

type RegistrationStep = "loading" | "idle" | "front" | "smile" | "left" | "right" | "complete";

const FaceRegisterPage = () => {
  const navigate = useNavigate();
  const [step, setStep] = useState<RegistrationStep>("idle");
  const [isUpdating, setIsUpdating] = useState(false);
  const [capturedDescriptors, setCapturedDescriptors] = useState<number[][]>([]);
  const videoRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const isCapturingRef = useRef(false);

  useEffect(() => {
    const init = async () => {
      setStep("loading");
      try {
        await loadFaceModels();
        setStep("idle");
      } catch (err) {
        toast.error("Failed to load face detection models.");
        setStep("idle");
      }
    };
    init();

    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const startRegistration = async () => {
    if (!videoRef.current) return;

    try {
      const stream = await startWebcam(videoRef.current);
      streamRef.current = stream;

      // Ensure video is ready before starting the process
      videoRef.current.onloadedmetadata = () => {
        setStep("front");
      };

      if (videoRef.current.readyState >= 2) {
        setStep("front");
      }
    } catch (err) {
      toast.error("Webcam access required for registration.");
      setStep("idle");
    }
  };

  useEffect(() => {
    if (["front", "smile", "left", "right"].includes(step) && !isCapturingRef.current) {
      const captureLoop = async () => {
        if (!videoRef.current || isCapturingRef.current) return;

        if (videoRef.current.videoWidth === 0) {
          // Wait for video dimensions
          setTimeout(captureLoop, 300);
          return;
        }

        const descriptor = await getFaceDescriptor(videoRef.current);
        if (descriptor) {
          isCapturingRef.current = true;
          const descriptorArray = Array.from(descriptor);

          setCapturedDescriptors(prev => [...prev, descriptorArray]);
          console.log(`Captured ${step} orientation`);

          // Show feedback before moving to next step
          setTimeout(() => {
            isCapturingRef.current = false;
            if (step === "front") setStep("smile");
            else if (step === "smile") setStep("left");
            else if (step === "left") setStep("right");
            else if (step === "right") {
              setStep("complete");
              toast.success("All angles captured successfully!");
            }
          }, 1500);
        } else {
          // Retry detection
          setTimeout(captureLoop, 300);
        }
      };

      captureLoop();
    }
  }, [step]);

  useEffect(() => {
    if (step === "complete" && capturedDescriptors.length === 4 && !isUpdating) {
      handleSaveRegistration();
    }
  }, [step, capturedDescriptors, isUpdating]);

  const handleSaveRegistration = async () => {
    if (capturedDescriptors.length < 4) return;

    setIsUpdating(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("No user found");

      // Store multiple descriptors in the 'faces' table as an array of arrays
      const { error: faceError } = await supabase
        .from('faces')
        .insert([{
          user_id: user.id,
          encoding: capturedDescriptors // JSONB array of number arrays
        }]);

      if (faceError) throw faceError;

      const { error: profileError } = await supabase
        .from('profiles')
        .update({ has_face_registered: true })
        .eq('id', user.id);

      if (profileError) throw profileError;

      toast.success("Security profile created!");

      // Force reload to let App.tsx re-fetch profile and cleanly route to /chat
      window.location.href = "/chat";
    } catch (error: any) {
      toast.error("Database Error: " + (error.message || "Failed to finalize registration. Please check Supabase policies."));
      console.error(error);
    } finally {
      setIsUpdating(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center relative overflow-hidden bg-background">
      <AnimatedBackground />

      <div className="relative z-10 w-full max-w-lg px-6 animate-fade-in">
        <div className="text-center mb-8">
          <h1 className="text-2xl font-bold text-foreground mb-2">Biometric Enrollment</h1>
          <p className="text-muted-foreground text-sm">Capturing multiple angles for maximum security</p>
        </div>

        <GlassCard strong className="p-8 flex flex-col items-center">
          <div className="relative w-56 h-56 mb-8">
            <div className={cn(
              "absolute inset-0 rounded-full border-2 border-dashed transition-all duration-500",
              ["front", "smile", "left", "right"].includes(step) && "border-primary animate-spin-slow",
              step === "complete" && "border-accent",
              step === "idle" && "border-border"
            )} />

            <div className={cn(
              "absolute inset-2 rounded-full transition-all duration-700",
              ["front", "smile", "left", "right"].includes(step) && "neon-glow-blue animate-pulse-glow",
              step === "complete" && "neon-glow-green",
            )} />

            <div className={cn(
              "absolute inset-4 rounded-full flex items-center justify-center transition-all duration-500 overflow-hidden bg-muted/40"
            )}>
              <video 
                ref={videoRef}
                autoPlay 
                muted 
                playsInline
                className={cn(
                  "absolute inset-0 w-full h-full object-cover scale-x-[-1]",
                  ["front", "smile", "left", "right", "complete"].includes(step) ? "opacity-100" : "opacity-0"
                )}
              />

              {isCapturingRef.current && (
                <div className="absolute inset-0 bg-primary/20 backdrop-blur-[2px] flex items-center justify-center animate-in fade-in zoom-in duration-300">
                  <div className="bg-primary/80 p-3 rounded-full">
                    <Check className="w-8 h-8 text-white" />
                  </div>
                </div>
              )}

              {step === "idle" && <User className="w-16 h-16 text-muted-foreground/40" />}
              {step === "loading" && <Loader2 className="w-10 h-10 text-primary animate-spin" />}
            </div>

            {/* Instruction Labels */}
            {["front", "smile", "left", "right"].includes(step) && (
              <div className="absolute -top-12 left-1/2 -translate-x-1/2 whitespace-nowrap bg-background/80 backdrop-blur px-4 py-1.5 rounded-full border border-primary/30 text-xs font-bold text-primary animate-bounce">
                {step === "front" && "LOOK STRAIGHT AT CAMERA"}
                {step === "smile" && "GIVE A SLIGHT SMILE"}
                {step === "left" && "TURN HEAD SLIGHTLY LEFT"}
                {step === "right" && "TURN HEAD SLIGHTLY RIGHT"}
              </div>
            )}
          </div>

          <div className="w-full space-y-6">
            <div className="flex justify-between items-center px-2">
              {[
                { id: "front", label: "Neutral" },
                { id: "smile", label: "Smile" },
                { id: "left", label: "Left" },
                { id: "right", label: "Right" }
              ].map((s, i) => (
                <div key={s.id} className="flex flex-col items-center gap-2">
                  <div className={cn(
                    "w-8 h-8 rounded-full flex items-center justify-center border-2 transition-all duration-500",
                    capturedDescriptors.length > i 
                      ? "bg-accent/20 border-accent text-accent" 
                      : step === s.id 
                        ? "bg-primary/20 border-primary text-primary animate-pulse" 
                        : "border-muted text-muted-foreground"
                  )}>
                    {capturedDescriptors.length > i ? <Check className="w-4 h-4" /> : i + 1}
                  </div>
                  <span className="text-[10px] uppercase tracking-wider font-bold opacity-70">{s.label}</span>
                </div>
              ))}
            </div>

            <p className="text-sm font-medium text-center text-muted-foreground min-h-[40px]">
              {step === "loading" && "Initializing security modules..."}
              {step === "idle" && "We need 4 quick snapshots to secure your identity."}
              {step === "front" && !isCapturingRef.current && "Stay still, capturing neutral face..."}
              {step === "smile" && !isCapturingRef.current && "Good! Now give a slight smile..."}
              {step === "left" && !isCapturingRef.current && "Now turn your head slightly to the left..."}
              {step === "right" && !isCapturingRef.current && "Almost done! Turn slightly to the right..."}
              {isCapturingRef.current && "Snapshot captured!"}
              {step === "complete" && "All angles secured. Encryption keys ready."}
            </p>

            {step === "idle" && (
              <GlowButton onClick={startRegistration} className="w-full">
                Begin Secure Setup
              </GlowButton>
            )}

            {step === "complete" && (
              <GlowButton onClick={handleSaveRegistration} className="w-full animate-fade-in" disabled={isUpdating}>
                {isUpdating ? "Securing Vault..." : "Finalize & Enter Chat"}
                {!isUpdating && <ArrowRight className="ml-2 w-4 h-4" />}
              </GlowButton>
            )}

            <button
              onClick={async () => {
                await supabase.auth.signOut();
                navigate("/");
              }}
              className="w-full mt-2 py-2 text-xs text-muted-foreground hover:text-foreground transition-colors"
            >
              Cancel Registration
            </button>
          </div>
        </GlassCard>
      </div>

      <style>{`
        .animate-spin-slow {
          animation: spin 8s linear infinite;
        }
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

export default FaceRegisterPage;

import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { AnimatedBackground } from "@/components/secure-chat/AnimatedBackground";
import { GlassCard } from "@/components/secure-chat/GlassCard";
import { GlowButton } from "@/components/secure-chat/GlowButton";
import { FloatingInput } from "@/components/secure-chat/FloatingInput";
import { Shield, Lock, Fingerprint, MessageSquare } from "lucide-react";
import { supabase } from "@/lib/supabase";
import { toast } from "sonner";

const LoginPage = () => {
  const navigate = useNavigate();
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    try {
      if (isLogin) {
        const { error } = await supabase.auth.signInWithPassword({
          email,
          password,
        });
        if (error) throw error;
        toast.success("Welcome back!");
      } else {
        const { data, error } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: {
              full_name: name,
            },
          },
        });
        if (error) throw error;

        if (data.user) {
          // Create the profile entry immediately with required email field
          const { error: profileError } = await supabase
            .from('profiles')
            .insert([{ 
              id: data.user.id, 
              email: data.user.email,
              has_face_registered: false 
            }]);

          if (profileError) {
            console.warn("Profile creation failed, App will retry on next check:", profileError);
          }
        }

        toast.success("Account created! You can now register your face.");
      }
    } catch (error: any) {
      toast.error(error.message || "An error occurred");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex relative overflow-hidden bg-background">
      <AnimatedBackground />

      {/* Left Panel - Branding */}
      <div className="hidden lg:flex flex-1 flex-col justify-center items-center relative z-10 p-12">
        <div className="animate-fade-in max-w-md">
          {/* Logo */}
          <div className="flex items-center gap-3 mb-8">
            <div className="w-12 h-12 rounded-2xl gradient-btn flex items-center justify-center neon-glow-blue">
              <Shield className="w-6 h-6 text-primary-foreground" />
            </div>
            <h1 className="text-3xl font-bold text-foreground">
              Secure<span className="text-gradient">Chat</span>
            </h1>
          </div>

          <h2 className="text-4xl font-bold text-foreground leading-tight mb-4">
            Your messages.{" "}
            <span className="text-gradient">Your face.</span>{" "}
            Your privacy.
          </h2>

          <p className="text-muted-foreground text-lg mb-10 leading-relaxed">
            AI-powered face detection ensures only you can read your messages. 
            Next-gen encryption meets biometric security.
          </p>

          {/* Feature pills */}
          <div className="flex flex-wrap gap-3">
            {[
              { icon: Lock, label: "End-to-End Encrypted" },
              { icon: Fingerprint, label: "Face ID Protection" },
              { icon: MessageSquare, label: "Real-time Messaging" },
            ].map(({ icon: Icon, label }) => (
              <div key={label} className="glass rounded-full px-4 py-2 flex items-center gap-2 text-sm text-muted-foreground">
                <Icon className="w-4 h-4 text-primary" />
                {label}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Right Panel - Form */}
      <div className="flex-1 flex items-center justify-center relative z-10 p-6">
        <GlassCard strong className="w-full max-w-md p-8 animate-scale-in">
          {/* Mobile logo */}
          <div className="lg:hidden flex items-center gap-2 mb-6 justify-center">
            <div className="w-10 h-10 rounded-xl gradient-btn flex items-center justify-center">
              <Shield className="w-5 h-5 text-primary-foreground" />
            </div>
            <span className="text-xl font-bold">Secure<span className="text-gradient">Chat</span></span>
          </div>

          {/* Tab toggle */}
          <div className="flex rounded-xl bg-muted/50 p-1 mb-8">
            <button
              onClick={() => setIsLogin(true)}
              className={`flex-1 py-2.5 rounded-lg text-sm font-medium transition-all duration-300 ${
                isLogin ? "bg-primary text-primary-foreground shadow-lg" : "text-muted-foreground hover:text-foreground"
              }`}
            >
              Login
            </button>
            <button
              onClick={() => setIsLogin(false)}
              className={`flex-1 py-2.5 rounded-lg text-sm font-medium transition-all duration-300 ${
                !isLogin ? "bg-primary text-primary-foreground shadow-lg" : "text-muted-foreground hover:text-foreground"
              }`}
            >
              Sign Up
            </button>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            {!isLogin && (
              <div className="animate-fade-in">
                <FloatingInput label="Full Name" value={name} onChange={(e) => setName(e.target.value)} />
              </div>
            )}
            <FloatingInput label="Email" type="email" value={email} onChange={(e) => setEmail(e.target.value)} />
            <FloatingInput label="Password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} />

            {isLogin && (
              <div className="text-right">
                <button type="button" className="text-xs text-primary hover:text-primary/80 transition-colors">
                  Forgot password?
                </button>
              </div>
            )}

            <GlowButton type="submit" className="w-full mt-2" disabled={isLoading}>
              {isLoading ? (isLogin ? "Signing in..." : "Creating account...") : (isLogin ? "Sign In" : "Create Account")}
            </GlowButton>
          </form>

          {/* Divider */}
          <div className="flex items-center gap-3 my-6">
            <div className="flex-1 h-px bg-border" />
            <span className="text-xs text-muted-foreground">or continue with</span>
            <div className="flex-1 h-px bg-border" />
          </div>

          {/* Social buttons */}
          <div className="grid grid-cols-2 gap-3">
            <GlowButton variant="secondary" size="sm" type="button">
              Google
            </GlowButton>
            <GlowButton variant="secondary" size="sm" type="button">
              GitHub
            </GlowButton>
          </div>

          <p className="text-center text-xs text-muted-foreground mt-6">
            By continuing, you agree to our Terms & Privacy Policy
          </p>
        </GlassCard>
      </div>
    </div>
  );
};

